import { useState } from "react";
import { createPost } from "../firebase/posts";
import AIWritingAssistant from "./ai/AIWritingAssistant";
import AITagGenerator from "./ai/AITagGenerator";
import { generateBlog } from "../ai/aiService";
import toast, { Toaster } from "react-hot-toast";

export default function WriteModal({ onClose, onPublished, isDemo, onDemoPublish, currentUser }) {
  const [form, setForm] = useState({
    title: "",
    author: currentUser?.displayName || "",
    content: "",
  });

  const [aiTags, setAiTags] = useState([]);
  const [activeTab, setActiveTab] = useState("write");
  const [publishing, setPublishing] = useState(false);

  const [aiDraft, setAiDraft] = useState("");
  const [showPreview, setShowPreview] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);

  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  // ✅ AI GENERATE (Improved)
  const handleGenerateBlog = async () => {
    if (!form.title.trim()) {
      toast.error("Enter title first");
      return;
    }

    setAiLoading(true);
    setShowPreview(true);

    try {
      const content = await generateBlog(form.title);
      setAiDraft(content);
      toast.success("AI draft ready!");
    } catch {
      toast.error("AI failed");
    }

    setAiLoading(false);
  };

  // ✅ PUBLISH
  const handlePublish = async () => {
    if (!form.title || !form.content) {
      toast.error("Fill all fields");
      return;
    }

    setPublishing(true);

    const postData = { ...form, tags: aiTags };

    if (isDemo) {
      onDemoPublish?.(postData);
    } else {
      await createPost(postData);
    }

    toast.success("Post published!");
    onPublished?.();
    onClose();
  };

  return (
    <>
      {/* ✅ TOASTER FIX (no blur) */}
      <Toaster
        position="top-right"
        toastOptions={{
          style: {
            zIndex: 99999,
          },
        }}
      />

      <div style={s.backdrop}>
        <div style={s.modal}>
          <button style={s.closeBtn} onClick={onClose}>✕</button>

          <h2 style={s.title}>✍️ Write Post</h2>

          {/* TABS */}
          <div style={s.tabs}>
            <button
              style={activeTab === "write" ? s.activeTab : s.tab}
              onClick={() => setActiveTab("write")}
            >
              Write
            </button>
            <button
              style={activeTab === "ai" ? s.activeTab : s.tab}
              onClick={() => setActiveTab("ai")}
            >
              AI Tools
            </button>
          </div>

          {/* WRITE TAB */}
          {activeTab === "write" && (
            <>
              <input
                style={s.input}
                placeholder="Enter post title..."
                value={form.title}
                onChange={(e) => set("title", e.target.value)}
              />

              <textarea
                style={s.textarea}
                placeholder="Write your content..."
                value={form.content}
                onChange={(e) => set("content", e.target.value)}
              />

              <AITagGenerator
                title={form.title}
                content={form.content}
                onTagsGenerated={setAiTags}
              />

              <div style={s.tags}>
                {aiTags.map((t) => (
                  <span key={t} style={s.tag}>#{t}</span>
                ))}
              </div>

              <button style={s.publishBtn} onClick={handlePublish}>
                {publishing ? "Publishing..." : "🚀 Publish"}
              </button>
            </>
          )}

          {/* AI TAB */}
          {activeTab === "ai" && (
            <>
              <button style={s.aiBtn} onClick={handleGenerateBlog}>
                ✨ Generate Blog with AI
              </button>

              {showPreview && (
                <div style={s.previewBox}>
                  <h4 style={s.previewTitle}>🤖 AI Draft</h4>

                  {aiLoading ? (
                    <p style={s.loading}>🤖 Writing a detailed blog... please wait</p>
                  ) : (
                    <div style={s.previewContent}>{aiDraft}</div>
                  )}

                  {!aiLoading && (
                    <div style={s.previewActions}>
                      <button
                        style={s.acceptBtn}
                        onClick={() => {
                          // ✅ Append instead of replace
                          setForm((f) => ({
                            ...f,
                            content: f.content
                              ? f.content + "\n\n" + aiDraft
                              : aiDraft,
                          }));
                          setShowPreview(false);
                          setActiveTab("write");
                        }}
                      >
                        ✅ Use
                      </button>

                      <button style={s.regenBtn} onClick={handleGenerateBlog}>
                        🔄 Regenerate
                      </button>

                      <button
                        style={s.rejectBtn}
                        onClick={() => setShowPreview(false)}
                      >
                        ❌ Close
                      </button>
                    </div>
                  )}
                </div>
              )}

              <AIWritingAssistant
                title={form.title}
                content={form.content}
              />
            </>
          )}
        </div>
      </div>
    </>
  );
}

const s = {
  backdrop: {
    position: "fixed",
    inset: 0,
    background: "rgba(15,23,42,0.6)",
    backdropFilter: "blur(6px)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    zIndex: 1000, // ✅ FIXED (was 9999)
  },

  modal: {
    background: "#ffffff",
    padding: "24px",
    borderRadius: "18px",
    width: "560px",
    boxShadow: "0 20px 60px rgba(0,0,0,0.2)",
    position: "relative",
    zIndex: 10000,
    animation: "fadeIn 0.3s ease",
  },

  closeBtn: {
    position: "absolute",
    top: 14,
    right: 14,
    border: "none",
    background: "#f1f5f9",
    borderRadius: "50%",
    width: 32,
    height: 32,
    cursor: "pointer",
  },

  title: {
    fontSize: "1.5rem",
    fontWeight: 700,
    marginBottom: 16,
  },

  tabs: {
    display: "flex",
    gap: 8,
    marginBottom: 16,
  },

  tab: {
    padding: "6px 14px",
    borderRadius: 8,
    border: "1px solid #e5e7eb",
    background: "#f8fafc",
    cursor: "pointer",
  },

  activeTab: {
    padding: "6px 14px",
    borderRadius: 8,
    background: "#2563eb",
    color: "#fff",
    fontWeight: 600,
  },

  input: {
    width: "100%",
    padding: "12px",
    borderRadius: 10,
    border: "1px solid #e5e7eb",
    marginBottom: 12,
  },

  textarea: {
    width: "100%",
    height: 140,
    padding: "12px",
    borderRadius: 10,
    border: "1px solid #e5e7eb",
    marginBottom: 14,
    lineHeight: 1.5,
  },

  tags: {
    marginBottom: 12,
  },

  tag: {
    background: "#eef2ff",
    padding: "6px 10px",
    borderRadius: 20,
    marginRight: 6,
    fontSize: "0.8rem",
  },

  publishBtn: {
    width: "100%",
    padding: "12px",
    borderRadius: 10,
    background: "linear-gradient(135deg,#2563eb,#1d4ed8)",
    color: "#fff",
    fontWeight: 600,
    border: "none",
    cursor: "pointer",
    boxShadow: "0 6px 20px rgba(37,99,235,0.3)",
  },

  aiBtn: {
    width: "100%",
    padding: "10px",
    borderRadius: 10,
    background: "#f1f5f9",
    border: "1px solid #e5e7eb",
    marginBottom: 12,
    cursor: "pointer",
  },

  previewBox: {
    border: "1px solid #e5e7eb",
    padding: 14,
    borderRadius: 12,
    background: "#f8fafc",
  },

  previewTitle: {
    marginBottom: 8,
    fontWeight: 600,
  },

  previewContent: {
    maxHeight: 300, // ✅ increased
    overflow: "auto",
    marginBottom: 10,
    lineHeight: 1.6,
    whiteSpace: "pre-line", // ✅ formatting fix
  },

  previewActions: {
    display: "flex",
    gap: 8,
  },

  acceptBtn: {
    flex: 1,
    background: "#16a34a",
    color: "#fff",
    border: "none",
    borderRadius: 8,
    padding: "8px",
  },

  regenBtn: {
    flex: 1,
    borderRadius: 8,
    padding: "8px",
    border: "1px solid #e5e7eb",
    background: "#fff",
  },

  rejectBtn: {
    flex: 1,
    borderRadius: 8,
    padding: "8px",
    border: "1px solid #e5e7eb",
    background: "#fff",
  },

  loading: {
    fontStyle: "italic",
    color: "#64748b",
  },
};
